%% Check if total cost exceeds budget. Budget of 0 means unlimited.
is_over_budget(State, Budget, Result) :-
    (Budget =< 0 ->
        Result = false
    ;
    (State.total_cost >= Budget -> Result = true ; Result = false)
    ).

%% Return remaining budget in USD. Budget of 0 means unlimited (returns -1).
budget_remaining(State, Budget, Result) :-
    (Budget =< 0 ->
        Result = -1.0
    ;
    Result is max(0.0, Budget - State.total_cost)
    ).

%% Reset all cost tracking state.
reset(State, State1) :-
    put_dict(records, State, [], State1),
    put_dict(total_input_tokens, State, 0, State1),
    put_dict(total_output_tokens, State, 0, State1),
    put_dict(total_cost, State, 0.0, State1).

%% Compute cost from token count and price per 1M tokens.
cost_compute(Tokens, Price_per_million, Result) :-
    Result is ((float(Tokens) * Price_per_million) / 1.0e+06).

%% Record a usage entry and update running totals.
record_usage(State, Input_tokens, Output_tokens, _Model, State1) :-
    NewVal is State.total_input_tokens + Input_tokens, put_dict(total_input_tokens, State, NewVal, State1),
    NewVal is State.total_output_tokens + Output_tokens, put_dict(total_output_tokens, State, NewVal, State1).

%% Return total token count (input + output).
total_tokens(State, Result) :-
    Result is (State.total_input_tokens + State.total_output_tokens).

%% Format a one-line cost summary showing totals.
get_summary(State, Result) :-
    format(atom(Result), "$~w (~w input, ~w output)", [State.total_cost, State.total_input_tokens, State.total_output_tokens]).

%% Set the per-token pricing for input and output.
set_pricing(State, Input_price, Output_price, State1) :-
    put_dict(Input_price, State, Input_price, State1),
    put_dict(Output_price, State, Output_price, State1).

%% Compute the average cost per token. Returns 0.0 if no tokens used.
cost_per_token(State, Result) :-
    Total = (State.total_input_tokens + State.total_output_tokens),
    (Total =< 0 ->
        Result = 0.0
    ;
    Result is (State.total_cost / float(Total))
    ).

%% Check if any usage records have been logged.
has_records(State, Result) :-
    \+ length(State.records, Result) =:= 0.

%% Return total token count (input + output).
total_tokens(State, Result) :-
    Result is (State.total_input_tokens + State.total_output_tokens).

%% Return a short cost summary string (e.g. $0.05).
cost_summary_short(State, Result) :-
    format(atom(Result), "$~w", [State.total_cost]).

%% Check if the current model has zero cost (total_cost == 0 after usage).
is_free_model(State, Result) :-
    (State.total_cost =:= 0 -> Result = true ; Result = false).

%% Compute ratio of input to output tokens. Returns 0.0 if no output tokens.
input_output_ratio(State, Result) :-
    (State.total_output_tokens =:= 0 ->
        Result = 0.0
    ;
    Result is (float(State.total_input_tokens) / float(State.total_output_tokens))
    ).

%% Calculate average cost per message. Returns 0.0 if no messages recorded.
average_cost_per_message(State, Result) :-
    (State.message_count =:= 0 ->
        Result = 0.0
    ;
    Result is (float(State.total_cost) / float(State.message_count))
    ).

%% Check if cost tracking is active (has recorded any usage).
is_tracking(State, Result) :-
    (State.message_count > 0 -> Result = true ; Result = false).

%% Calculate average cost per input token. Returns 0.0 if no input tokens recorded.
cost_per_input_token(State, Result) :-
    (State.total_input_tokens =:= 0 ->
        Result = 0.0
    ;
    Result is (float(State.total_cost) / float(State.total_input_tokens))
    ).

%% Return the total number of messages tracked by the cost tracker.
total_messages(State, Result) :-
    Result = State.message_count.

%% Check if total cost exceeds a given threshold.
cost_exceeds(State, Threshold, Result) :-
    (State.total_cost > Threshold -> Result = true ; Result = false).

%% Return the ratio of input tokens to total tokens. Returns 0.0 if no tokens.
input_ratio(State, Result) :-
    ((State.total_input_tokens + State.total_output_tokens) =:= 0 ->
        Result = 0.0
    ;
    Result is (float(State.total_input_tokens) / float((State.total_input_tokens + State.total_output_tokens)))
    ).

%% Format a cost amount as a dollar string (e.g. $1.50).
format_dollars(Amount, Result) :-
    format(atom(Result), "$~w", [Amount]).

%% Check if any tokens have been tracked (input or output > 0).
has_usage(State, Result) :-
    ((State.total_input_tokens + State.total_output_tokens) > 0 -> Result = true ; Result = false).


%% Cost tracker using dynamic state
:- dynamic cost_state/3.  %% cost_state(TrackerID, TotalInputTokens, TotalOutputTokens)

cost_tracker_init(ID) :-
    retractall(cost_state(ID, _, _)),
    assert(cost_state(ID, 0, 0)).

cost_tracker_add(ID, Model, InputTokens, OutputTokens) :-
    retract(cost_state(ID, OldIn, OldOut)),
    NewIn is OldIn + InputTokens,
    NewOut is OldOut + OutputTokens,
    assert(cost_state(ID, NewIn, NewOut)),
    (model_pricing(Model, InPrice, OutPrice) ->
        Cost is (InputTokens * InPrice + OutputTokens * OutPrice) / 1000000,
        format("  [cost: $~4f (~w in, ~w out)]~n", [Cost, InputTokens, OutputTokens])
    ; true).

cost_tracker_total(ID, Total) :-
    cost_state(ID, TotalIn, TotalOut),
    Total = tokens(TotalIn, TotalOut).

cost_tracker_format(ID, Formatted) :-
    cost_state(ID, TotalIn, TotalOut),
    format(atom(Formatted), "~w input, ~w output tokens", [TotalIn, TotalOut]).
